1	`timescale 1ns / 1ps
2	
3	/**
4	 * range_bin_decimator.v
5	 *
6	 * Reduces 1024 range bins from the matched filter output down to 64 bins
7	 * for the Doppler processor. Supports multiple decimation modes:
8	 *
9	 *   Mode 2'b00: Simple decimation (take every Nth sample)
10	 *   Mode 2'b01: Peak detection (select max-magnitude sample from each group)
11	 *   Mode 2'b10: Averaging (sum group and divide by N)
12	 *   Mode 2'b11: Reserved
13	 *
14	 * Interface contract (from radar_receiver_final.v line 229):
15	 *   .clk, .reset_n
16	 *   .range_i_in, .range_q_in, .range_valid_in   ← from matched_filter output
17	 *   .range_i_out, .range_q_out, .range_valid_out → to Doppler processor
18	 *   .range_bin_index                             → 6-bit output bin index
19	 *   .decimation_mode                             ← 2-bit mode select
20	 *   .start_bin                                   ← 10-bit start offset
21	 *
22	 * start_bin usage:
23	 *   When start_bin > 0, the decimator skips the first 'start_bin' valid
24	 *   input samples before beginning decimation. This allows selecting a
25	 *   region of interest within the 1024 range bins (e.g., to focus on
26	 *   near-range or far-range targets). When start_bin = 0 (default),
27	 *   all 1024 bins are processed starting from bin 0.
28	 *
29	 * Clock domain: clk (100 MHz)
30	 * Decimation: 1024 → 64 (factor of 16)
31	 */
32	
33	module range_bin_decimator #(
34	    parameter INPUT_BINS        = 1024,
35	    parameter OUTPUT_BINS       = 64,
36	    parameter DECIMATION_FACTOR = 16
37	) (
38	    input wire clk,
39	    input wire reset_n,
40	
41	    // Input from matched filter
42	    input wire signed [15:0] range_i_in,
43	    input wire signed [15:0] range_q_in,
44	    input wire range_valid_in,
45	
46	    // Output to Doppler processor
47	    output reg signed [15:0] range_i_out,
48	    output reg signed [15:0] range_q_out,
49	    output reg range_valid_out,
50	    output reg [5:0] range_bin_index,
51	
52	    // Configuration
53	    input wire [1:0] decimation_mode,  // 00=decimate, 01=peak, 10=average
54	    input wire [9:0] start_bin,        // First input bin to process
55	
56	    // Diagnostics
57	    output reg watchdog_timeout        // Pulses high for 1 cycle on watchdog reset
58	
59	`ifdef FORMAL
60	    ,
61	    output wire [2:0]  fv_state,
62	    output wire [9:0]  fv_in_bin_count,
63	    output wire [3:0]  fv_group_sample_count,
64	    output wire [5:0]  fv_output_bin_count,
65	    output wire [9:0]  fv_skip_count
66	`endif
67	);
68	
69	// Fix 5: Watchdog timeout — if no valid input arrives for WATCHDOG_LIMIT
70	// clocks while in ST_PROCESS or ST_SKIP, return to ST_IDLE to prevent hang.
71	// 256 clocks at 100MHz = 2.56us, well beyond normal inter-sample gap.
72	localparam WATCHDOG_LIMIT = 10'd256;
73	
74	// ============================================================================
75	// INTERNAL SIGNALS
76	// ============================================================================
77	
78	// Input bin counter (0..1023)
79	reg [9:0] in_bin_count;
80	
81	// Group tracking
82	reg [3:0] group_sample_count;  // 0..15 within current group of 16
83	reg [5:0] output_bin_count;    // 0..63 output bin index
84	
85	// State machine
86	reg [2:0] state;
87	localparam ST_IDLE    = 3'd0;
88	localparam ST_SKIP    = 3'd1;  // Skip first start_bin samples
89	localparam ST_PROCESS = 3'd2;
90	localparam ST_EMIT    = 3'd3;
91	localparam ST_DONE    = 3'd4;
92	
93	// Skip counter for start_bin
94	reg [9:0] skip_count;
95	
96	// Watchdog counter — counts consecutive clocks with no range_valid_in
97	reg [9:0] watchdog_count;
98	
99	`ifdef FORMAL
100	assign fv_state              = state;
101	assign fv_in_bin_count       = in_bin_count;
102	assign fv_group_sample_count = group_sample_count;
103	assign fv_output_bin_count   = output_bin_count;
104	assign fv_skip_count         = skip_count;
105	`endif
106	
107	// ============================================================================
108	// PEAK DETECTION (Mode 01)
109	// ============================================================================
110	// Track the sample with the largest magnitude in the current group of 16
111	reg signed [15:0] peak_i, peak_q;
112	reg [16:0] peak_mag;  // |I| + |Q| approximation
113	wire [16:0] cur_mag;
114	
115	// Magnitude approximation: |I| + |Q| (avoids multiplier for sqrt(I²+Q²))
116	wire [15:0] abs_i = range_i_in[15] ? (~range_i_in + 1) : range_i_in;
117	wire [15:0] abs_q = range_q_in[15] ? (~range_q_in + 1) : range_q_in;
118	assign cur_mag = {1'b0, abs_i} + {1'b0, abs_q};
119	
120	// ============================================================================
121	// AVERAGING (Mode 10)
122	// ============================================================================
123	// Accumulate I and Q separately, then divide by DECIMATION_FACTOR (>>4)
124	reg signed [19:0] sum_i, sum_q;  // 16 + 4 guard bits for sum of 16 values
125	
126	// ============================================================================
127	// SIMPLE DECIMATION (Mode 00)
128	// ============================================================================
129	// Just take sample at offset (group_start + DECIMATION_FACTOR/2) for center
130	reg signed [15:0] decim_i, decim_q;
131	
132	// ============================================================================
133	// MAIN STATE MACHINE
134	// ============================================================================
135	always @(posedge clk or negedge reset_n) begin
136	    if (!reset_n) begin
137	        state             <= ST_IDLE;
138	        in_bin_count      <= 10'd0;
139	        group_sample_count <= 4'd0;
140	        output_bin_count  <= 6'd0;
141	        skip_count        <= 10'd0;
142	        watchdog_count    <= 10'd0;
143	        watchdog_timeout  <= 1'b0;
144	        range_valid_out   <= 1'b0;
145	        range_i_out       <= 16'd0;
146	        range_q_out       <= 16'd0;
147	        range_bin_index   <= 6'd0;
148	        peak_i            <= 16'd0;
149	        peak_q            <= 16'd0;
150	        peak_mag          <= 17'd0;
151	        sum_i             <= 20'd0;
152	        sum_q             <= 20'd0;
153	        decim_i           <= 16'd0;
154	        decim_q           <= 16'd0;
155	    end else begin
156	        // Default: output not valid, watchdog not triggered
157	        range_valid_out  <= 1'b0;
158	        watchdog_timeout <= 1'b0;
159	
160	        case (state)
161	        // ================================================================
162	        // IDLE: Wait for first valid input
163	        // ================================================================
164	        ST_IDLE: begin
165	            in_bin_count       <= 10'd0;
166	            group_sample_count <= 4'd0;
167	            output_bin_count   <= 6'd0;
168	            skip_count         <= 10'd0;
169	            watchdog_count     <= 10'd0;
170	            peak_i             <= 16'd0;
171	            peak_q             <= 16'd0;
172	            peak_mag           <= 17'd0;
173	            sum_i              <= 20'd0;
174	            sum_q              <= 20'd0;
175	
176	            if (range_valid_in) begin
177	                in_bin_count <= 10'd1;
178	
179	                if (start_bin > 10'd0) begin
180	                    // Need to skip 'start_bin' samples first
181	                    skip_count <= 10'd1;
182	                    state      <= ST_SKIP;
183	                end else begin
184	                    // No skip — process first sample immediately
185	                    state              <= ST_PROCESS;
186	                    group_sample_count <= 4'd1;
187	
188	                    // Mode-specific first sample handling
189	                    case (decimation_mode)
190	                    2'b00: begin  // Simple decimation — check if center sample
191	                        if (4'd0 == (DECIMATION_FACTOR / 2)) begin
192	                            decim_i <= range_i_in;
193	                            decim_q <= range_q_in;
194	                        end
195	                    end
196	                    2'b01: begin  // Peak detection
197	                        peak_i   <= range_i_in;
198	                        peak_q   <= range_q_in;
199	                        peak_mag <= cur_mag;
200	                    end
201	                    2'b10: begin  // Averaging
202	                        sum_i <= {{4{range_i_in[15]}}, range_i_in};
203	                        sum_q <= {{4{range_q_in[15]}}, range_q_in};
204	                    end
205	                    default: ;
206	                    endcase
207	                end
208	            end
209	        end
210	
211	        // ================================================================
212	        // SKIP: Discard input samples until start_bin reached
213	        // ================================================================
214	        ST_SKIP: begin
215	            if (range_valid_in) begin
216	                watchdog_count <= 10'd0;
217	                in_bin_count <= in_bin_count + 1;
218	
219	                if (skip_count >= start_bin) begin
220	                    // Done skipping — this sample is the first to process
221	                    state              <= ST_PROCESS;
222	                    group_sample_count <= 4'd1;
223	
224	                    case (decimation_mode)
225	                    2'b00: begin
226	                        if (4'd0 == (DECIMATION_FACTOR / 2)) begin
227	                            decim_i <= range_i_in;
228	                            decim_q <= range_q_in;
229	                        end
230	                    end
231	                    2'b01: begin
232	                        peak_i   <= range_i_in;
233	                        peak_q   <= range_q_in;
234	                        peak_mag <= cur_mag;
235	                    end
236	                    2'b10: begin
237	                        sum_i <= {{4{range_i_in[15]}}, range_i_in};
238	                        sum_q <= {{4{range_q_in[15]}}, range_q_in};
239	                    end
240	                    default: ;
241	                    endcase
242	                end else begin
243	                    skip_count <= skip_count + 1;
244	                end
245	            end else begin
246	                // No valid input — increment watchdog
247	                if (watchdog_count >= WATCHDOG_LIMIT - 1) begin
248	                    watchdog_timeout <= 1'b1;
249	                    state <= ST_IDLE;
250	                    `ifdef SIMULATION
251	                    $display("[RNG_DECIM] WATCHDOG: timeout in ST_SKIP after %0d idle clocks", WATCHDOG_LIMIT);
252	                    `endif
253	                end else begin
254	                    watchdog_count <= watchdog_count + 1;
255	                end
256	            end
257	        end
258	
259	        // ================================================================
260	        // PROCESS: Accumulate samples within each group of DECIMATION_FACTOR
261	        // ================================================================
262	        ST_PROCESS: begin
263	            if (range_valid_in) begin
264	                watchdog_count <= 10'd0;
265	                in_bin_count <= in_bin_count + 1;
266	
267	                // Mode-specific sample processing — always process
268	                // the current sample before checking overflow
269	                case (decimation_mode)
270	                2'b00: begin  // Simple decimation
271	                    if (group_sample_count == (DECIMATION_FACTOR / 2)) begin
272	                        decim_i <= range_i_in;
273	                        decim_q <= range_q_in;
274	                    end
275	                end
276	                2'b01: begin  // Peak detection
277	                    if (cur_mag > peak_mag) begin
278	                        peak_i   <= range_i_in;
279	                        peak_q   <= range_q_in;
280	                        peak_mag <= cur_mag;
281	                    end
282	                end
283	                2'b10: begin  // Averaging
284	                    sum_i <= sum_i + {{4{range_i_in[15]}}, range_i_in};
285	                    sum_q <= sum_q + {{4{range_q_in[15]}}, range_q_in};
286	                end
287	                default: ;
288	                endcase
289	
290	                // Check if group is complete
291	                if (group_sample_count == DECIMATION_FACTOR - 1) begin
292	                    // Group complete — emit output
293	                    state <= ST_EMIT;
294	                    group_sample_count <= 4'd0;
295	                end else if (in_bin_count >= INPUT_BINS - 1) begin
296	                    // Overflow guard: consumed all input bins but group
297	                    // is not yet complete. Stop to prevent corruption of
298	                    // downstream Doppler BRAM if matched filter emits
299	                    // more than INPUT_BINS valid samples.
300	                    state <= ST_DONE;
301	                end else begin
302	                    group_sample_count <= group_sample_count + 1;
303	                end
304	            end else begin
305	                // No valid input — increment watchdog
306	                if (watchdog_count >= WATCHDOG_LIMIT - 1) begin
307	                    watchdog_timeout <= 1'b1;
308	                    state <= ST_IDLE;
309	                    `ifdef SIMULATION
310	                    $display("[RNG_DECIM] WATCHDOG: timeout in ST_PROCESS after %0d idle clocks", WATCHDOG_LIMIT);
311	                    `endif
312	                end else begin
313	                    watchdog_count <= watchdog_count + 1;
314	                end
315	            end
316	        end
317	
318	        // ================================================================
319	        // EMIT: Output one decimated range bin
320	        // ================================================================
321	        ST_EMIT: begin
322	            range_valid_out <= 1'b1;
323	            range_bin_index <= output_bin_count;
324	
325	            case (decimation_mode)
326	            2'b00: begin  // Simple decimation
327	                range_i_out <= decim_i;
328	                range_q_out <= decim_q;
329	            end
330	            2'b01: begin  // Peak detection
331	                range_i_out <= peak_i;
332	                range_q_out <= peak_q;
333	            end
334	            2'b10: begin  // Averaging (sum >> 4 = divide by 16)
335	                range_i_out <= sum_i[19:4];
336	                range_q_out <= sum_q[19:4];
337	            end
338	            default: begin
339	                range_i_out <= 16'd0;
340	                range_q_out <= 16'd0;
341	            end
342	            endcase
343	
344	            // Reset group accumulators
345	            peak_i   <= 16'd0;
346	            peak_q   <= 16'd0;
347	            peak_mag <= 17'd0;
348	            sum_i    <= 20'd0;
349	            sum_q    <= 20'd0;
350	
351	            // Advance output bin
352	            output_bin_count <= output_bin_count + 1;
353	
354	            // Check if all output bins emitted
355	            if (output_bin_count == OUTPUT_BINS - 1) begin
356	                state <= ST_DONE;
357	            end else begin
358	                // If we already have valid input waiting, process it immediately
359	                if (range_valid_in) begin
360	                    state              <= ST_PROCESS;
361	                    group_sample_count <= 4'd1;
362	                    in_bin_count       <= in_bin_count + 1;
363	
364	                    case (decimation_mode)
365	                    2'b00: begin
366	                        if (4'd0 == (DECIMATION_FACTOR / 2)) begin
367	                            decim_i <= range_i_in;
368	                            decim_q <= range_q_in;
369	                        end
370	                    end
371	                    2'b01: begin
372	                        peak_i   <= range_i_in;
373	                        peak_q   <= range_q_in;
374	                        peak_mag <= cur_mag;
375	                    end
376	                    2'b10: begin
377	                        sum_i <= {{4{range_i_in[15]}}, range_i_in};
378	                        sum_q <= {{4{range_q_in[15]}}, range_q_in};
379	                    end
380	                    default: ;
381	                    endcase
382	                end else begin
383	                    state <= ST_PROCESS;
384	                    group_sample_count <= 4'd0;
385	                end
386	            end
387	        end
388	
389	        // ================================================================
390	        // DONE: All 64 output bins emitted, return to idle
391	        // ================================================================
392	        ST_DONE: begin
393	            state <= ST_IDLE;
394	
395	            `ifdef SIMULATION
396	            $display("[RNG_DECIM] Frame complete: %0d output bins emitted", OUTPUT_BINS);
397	            `endif
398	        end
399	
400	        default: state <= ST_IDLE;
401	        endcase
402	    end
403	end
404	
405	endmodule
